INSERT INTO `chatbot_scenarios` VALUES (1,NULL,NULL,_binary '','Shop mở cửa từ 8:00 đến 22:00 mỗi ngày.','giờ mở cửa,mấy giờ mở cửa,shop mở cửa','gio mo cua','Giờ mở cửa','TEXT','GENERAL',NULL),(3,'2026-04-08 08:04:05.000000','2026-04-08 08:04:05.000000',_binary '','Shop hỗ trợ đổi trả theo chính sách hiện hành. Bạn vui lòng giữ hóa đơn và sản phẩm còn nguyên tem mác nhé.','đổi trả,hoàn hàng,return,đổi size','đổi trả','Chính sách đổi trả','TEXT','BOTH',NULL),(7,'2026-04-09 02:19:08.000000','2026-04-09 02:19:08.000000',_binary '','Nếu bạn thích phong cách lịch sự: áo sơ mi + quần tây + giày da. Nếu thích trẻ trung: áo polo + quần jean/chinos + sneaker. Bạn muốn mình gợi ý theo kiểu đi làm hay đi chơi?','phối đồ,mặc sao đẹp,mix đồ,set đồ,outfit nam','goi y phoi do nam','Phối đồ nam','TEXT','GENERAL',NULL),(8,'2026-04-09 02:19:08.000000','2026-04-09 02:19:08.000000',_binary '','Shop thường có ưu đãi theo từng đợt và một số sản phẩm đang giảm giá trực tiếp trên website. Bạn có thể vào danh mục sản phẩm để xem mẫu đang có giá tốt nhé.','khuyến mãi,giảm giá,sale,ưu đãi,có deal không','shop co khuyen mai khong','Ưu đãi khuyến mãi','TEXT','GENERAL',NULL),(9,'2026-04-09 02:19:08.000000','2026-04-09 02:19:08.000000',_binary '','Phí vận chuyển sẽ tùy khu vực nhận hàng. Thời gian giao thường từ 1-5 ngày làm việc tùy tỉnh thành. Khi đặt hàng, hệ thống sẽ hiển thị phí ship cụ thể cho bạn nhé.','phí ship,ship bao nhiêu,giao hàng,mất bao lâu','phi van chuyen bao nhieu','Phí vận chuyển','TEXT','BOTH',NULL),(10,'2026-04-09 02:19:08.000000','2026-04-09 02:19:08.000000',_binary '','Shop có hỗ trợ các hình thức thanh toán phù hợp tùy đơn hàng. Bạn kiểm tra lúc đặt hàng hoặc nhắn admin để được hỗ trợ nhanh hơn nhé.','cod,thanh toán khi nhận hàng,ship cod,trả tiền mặt','co thanh toan cod khong','Thanh toán khi nhận hàng','SHOP_INFO','BOTH',NULL),(11,'2026-04-09 02:19:28.000000','2026-04-09 02:19:28.000000',_binary '','Mình gợi ý cho bạn một số mẫu áo sơ mi nổi bật của shop nè:','áo sơ mi,sơ mi,shirt,áo đi làm','toi muon xem ao so mi','Gợi ý áo sơ mi','PRODUCT_LIST','BOTH',NULL),(12,'2026-04-09 02:19:28.000000','2026-04-09 02:19:28.000000',_binary '','Đây là một số mẫu áo polo nam đang được quan tâm nhiều tại shop:','áo polo,polo,áo thun cổ bẻ','toi muon xem ao polo','Gợi ý áo polo','PRODUCT_LIST','BOTH',NULL),(13,'2026-04-09 02:19:28.000000','2026-04-09 02:19:28.000000',_binary '','Mình chọn sẵn cho bạn một số mẫu quần nam dễ mặc và đẹp nè:','quần nam,quần tây,quần jean,quần đi làm','toi muon xem quan nam','Gợi ý quần nam','PRODUCT_LIST','BOTH',NULL),(14,'2026-04-09 02:19:28.000000','2026-04-09 02:19:28.000000',_binary '','Đây là vài mẫu blazer nam lịch lãm mà bạn có thể tham khảo:','blazer,áo vest nhẹ,khoác blazer','toi muon xem blazer','Gợi ý blazer','PRODUCT_LIST','BOTH',NULL),(15,'2026-04-09 02:19:28.000000','2026-04-09 02:19:28.000000',_binary '','Mình gợi ý một số mẫu giày nam phù hợp nhiều phong cách nhé:','giày nam,giày da,giày đi làm,giày đẹp','toi muon xem giay nam','Gợi ý giày nam','PRODUCT_LIST','BOTH',NULL),(16,'2026-04-09 02:19:28.000000','2026-04-09 02:19:28.000000',_binary '','Đây là một số mẫu cà vạt giúp outfit nam nhìn chỉnh chu hơn:','cà vạt,caravat,cravat,tie','toi muon xem ca vat','Gợi ý cà vạt','PRODUCT_LIST','BOTH',NULL),(17,'2026-04-09 02:19:47.000000','2026-04-09 02:19:47.000000',_binary '','Bạn có muốn chuyển đến trang sản phẩm để xem đầy đủ các mẫu hiện có không?','xem sản phẩm,tất cả sản phẩm,danh mục sản phẩm,trang sản phẩm','toi muon xem tat ca san pham','Đi tới trang sản phẩm','NAVIGATE','GENERAL','SanPham.html'),(18,'2026-04-09 02:19:47.000000','2026-04-09 02:19:47.000000',_binary '','Bạn có muốn chuyển đến trang danh mục áo sơ mi không?','trang áo sơ mi,xem áo sơ mi,danh mục sơ mi','toi muon vao trang ao so mi','Đi tới trang áo sơ mi','NAVIGATE','GENERAL',NULL),(19,'2026-04-09 02:19:47.000000','2026-04-09 02:19:47.000000',_binary '','Bạn có muốn chuyển đến trang danh mục áo polo không?','trang áo polo,xem áo polo,danh mục polo','toi muon vao trang ao polo','Đi tới trang áo polo','NAVIGATE','GENERAL',NULL),(20,'2026-04-09 02:19:47.000000','2026-04-09 02:19:47.000000',_binary '','Bạn có muốn chuyển đến trang danh mục quần nam không?','trang quần,xem quần nam,danh mục quần','toi muon vao trang quan','Đi tới trang quần nam','NAVIGATE','GENERAL',NULL),(21,'2026-04-09 02:19:47.000000','2026-04-09 02:19:47.000000',_binary '','Bạn có muốn chuyển đến trang giỏ hàng ngay không?','giỏ hàng,xem giỏ hàng,cart','toi muon vao gio hang','Đi tới giỏ hàng','NAVIGATE','BOTH',NULL),(22,'2026-04-09 02:19:47.000000','2026-04-09 02:19:47.000000',_binary '','Bạn có muốn chuyển đến trang theo dõi đơn hàng không?','đơn hàng,theo dõi đơn,xem đơn hàng,đơn của tôi','toi muon xem don hang','Đi tới đơn hàng','NAVIGATE','BOTH',NULL),(23,'2026-04-09 02:19:47.000000','2026-04-09 02:19:47.000000',_binary '','Bạn có muốn chuyển đến trang liên hệ để được hỗ trợ nhanh hơn không?','liên hệ shop,chat admin,gọi shop,hỗ trợ trực tiếp','toi muon lien he shop','Đi tới liên hệ','NAVIGATE','BOTH','/contact.html'),(25,'2026-04-12 09:45:30.349036','2026-04-12 09:45:30.349036',_binary '','Men Fashion là cửa hàng chuyên cung cấp các sản phẩm thời trang nam như áo sơ mi, áo polo, quần, giày và phụ kiện. Bạn muốn mình gợi ý sản phẩm nào không?','shop,bán gì,cửa hàng','shop là gì,shop bán gì,cửa hàng này bán gì','Giới thiệu shop','TEXT','GENERAL',NULL),(26,'2026-04-12 22:06:50.967276','2026-04-12 22:06:50.967276',_binary '','Địa chỉ\nTrường Đại học Công nghệ Đồng Nai\n\nSố điện thoại\n0901 234 567','thông tin liên hệ,liên hệ,địa chỉ,số điện thoại,sdt,so dien thoai,contact','Thông tin liên hệ','Thông tin liên hệ','TEXT','GENERAL',NULL);
